mapper.select:
SELECT TBRC.ID, TBRC.POUND_ID, TBRC.POUND_NO, TBRC.PLAN_NO, TBRC.GOODS_NAME, TBRC.QUANTITY, TBRC.STATUS, TBRC.MAC_NO, TBRC.TRUCK_NO, TBRC.TALLY_ID, TBRC.PLAN_ID, TBRC.CONFIRM_START_TIME, TBRC.CONFIRM_END_TIME, TBRC.CREATE_BY, TBRC.CREATE_BY_NAME, TBRC.CREATE_TIME, TBRC.UPDATE_BY, TBRC.UPDATE_BY_NAME, TBRC.UPDATE_TIME, TBCI.ID AS CARGO_INFO_ID, TBCI.CARGO_INFO_NO, TBRC.STORAGE_YARD_NM, TBRC.RESERVATION_POUND_ID FROM T_BUS_RESERVATION_CONFIRM TBRC LEFT JOIN T_BUS_TRUST_CARGO TBTC ON TBRC.PLAN_NO = TBTC.BUSINESS_NO LEFT JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID
AND TBRC.STATUS = #{status}
AND TBRC.MAC_NO = #{macNo}
AND NVL(TBRC.WORK_TYPE,'2') = #{workType}

SELECT TBRC.ID, TBRC.POUND_ID, TBRC.POUND_NO, TBRC.PLAN_NO, TBRC.GOODS_NAME, TBRC.QUANTITY, TBRC.STATUS, TBRC.MAC_NO, TBRC.TRUCK_NO, TBRC.TALLY_ID, TBRC.PLAN_ID, TBRC.CONFIRM_START_TIME, TBRC.CONFIRM_END_TIME, TBRC.CREATE_BY, TBRC.CREATE_BY_NAME, TBRC.CREATE_TIME, TBRC.UPDATE_BY, TBRC.UPDATE_BY_NAME, TBRC.UPDATE_TIME, TBCI.ID AS CARGO_INFO_ID, TBCI.CARGO_INFO_NO, TBRC.STORAGE_YARD_NM, TBRC.RESERVATION_POUND_ID FROM T_BUS_RESERVATION_CONFIRM TBRC LEFT JOIN T_BUS_TRUST_CARGO TBTC ON TBRC.PLAN_NO = TBTC.BUSINESS_NO LEFT JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID
TBRC.STATUS = '1'
AND NVL(TBRC.WORK_TYPE,'2') = #{workType}
AND TBRC.MAC_NO = #{macNo}

SELECT ID, POUND_ID, POUND_NO, PLAN_NO, GOODS_NAME, QUANTITY, STATUS, MAC_NO, TRUCK_NO, TALLY_ID, PLAN_ID, CONFIRM_START_TIME, CONFIRM_END_TIME, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME FROM T_BUS_RESERVATION_CONFIRM
ID = #{id}
AND STATUS = #{status}
AND MAC_NO = #{macNo}

SELECT T1.NOTE_ID AS ID, T1.TRUCK_PLATE AS TRUCK_NO, T1.WEIGH_IN_DT AS IN_TIME, T1.GOODS_NAME AS CARGO_NAME, T2.DRIVER_NAME_ONE AS DRIVER, T2.DRIVER_PHONE_ONE AS PHONE, T1.CON_UNIT AS CARGO_OWNER_NAME, T4.CARGO_INFO_NO, NVL(T6.QUANTITY,0) QUANTITY FROM WFG_PORTMIS_POUND.WEIGHT_RECORD_POUND T1 LEFT JOIN T_BUS_VEHICLE_RESERVATION T2 ON T1.TSPT_ID = T2.TASK_NO LEFT JOIN T_BUS_TRUST_CARGO T3 ON T1.PLAN_NO = T3.BUSINESS_NO LEFT JOIN T_BUS_CARGO_INFO T4 ON T3.CARGO_INFO_ID = T4.ID LEFT JOIN T_BUS_RESERVATION_CONFIRM T6 ON T1.NOTE_ID = T6.POUND_ID
T1.IS_FINISHED = 0 AND T1.PORT_CODE = '01' AND T2.DRIVER_NAME_ONE IS NOT NULL
AND T3.CARGO_INFO_ID = #{cargoInfoId}
AND T1.TRUCK_PLATE LIKE #{truckNoLike}
AND T3.CARGO_INFO_ID in (SELECT T2.CARGO_INFO_ID FROM T_BUS_TRUST T1 LEFT JOIN T_BUS_TRUST_CARGO T2 ON T1.ID = T2.TRUST_ID WHERE T1.SHIPVOYAGE_ITEM_ID = #{shipVoyageItemId} AND ( T1.TYPE = '装船' OR T1.TYPE = '卸船' ))
ORDER BY T1.WEIGH_IN_DT
